import{_ as t,o as a,c as s,a2 as n}from"./chunks/framework.DfwzJIgY.js";const u=JSON.parse('{"title":"Operations & Deploy","description":"","frontmatter":{},"headers":[],"relativePath":"reference/operations.md","filePath":"reference/operations.md"}'),i={name:"reference/operations.md"};function o(r,e,d,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[n(`<h1 id="operations-deploy" tabindex="-1">Operations &amp; Deploy <a class="header-anchor" href="#operations-deploy" aria-label="Permalink to &quot;Operations &amp; Deploy&quot;">​</a></h1><p>Everything you need to run the app locally, manage the database, test, deploy, and debug infrastructure.</p><hr><h2 id="command-cheat-sheet" tabindex="-1">Command Cheat Sheet <a class="header-anchor" href="#command-cheat-sheet" aria-label="Permalink to &quot;Command Cheat Sheet&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>yarn s</code></td><td>Start the web server (nodemon, port 8000, dev env)</td></tr><tr><td><code>yarn w</code></td><td>Start the background worker (nodemon, dev env)</td></tr><tr><td><code>yarn cron</code></td><td>Start the cron/clock daemon (nodemon, dev env)</td></tr><tr><td><code>yarn lang</code></td><td>Compile <code>languages/*.js</code> → <code>locales/*.json</code> and validate all i18n keys</td></tr><tr><td><code>yarn gen &lt;Feature&gt;</code></td><td>Scaffold a new feature folder</td></tr><tr><td><code>yarn gen &lt;Feature&gt; -a V1Action</code></td><td>Scaffold a new action inside a feature</td></tr><tr><td><code>yarn gen &lt;Feature&gt; -t V1Task</code></td><td>Scaffold a new background task inside a feature</td></tr><tr><td><code>yarn gen &lt;Feature&gt; -m Mailer</code></td><td>Scaffold a new mailer inside a feature</td></tr><tr><td><code>yarn del &lt;Feature&gt; -a V1Action</code></td><td>Remove a scaffolded action (also removes its export from <code>actions/index.js</code>)</td></tr><tr><td><code>yarn del &lt;Feature&gt; -t V1Task</code></td><td>Remove a scaffolded task</td></tr><tr><td><code>yarn mg</code> / <code>yarn migrate</code></td><td>Run pending migrations (development)</td></tr><tr><td><code>yarn migrate:prod</code></td><td>Run pending migrations (production)</td></tr><tr><td><code>yarn rb</code> / <code>yarn rollback</code></td><td>Roll back the last migration (development)</td></tr><tr><td><code>yarn rollback:prod</code></td><td>Roll back the last migration (production)</td></tr><tr><td><code>yarn backup</code></td><td><code>pg_dump</code> the dev DB to <code>database/backups/backup.sql</code></td></tr><tr><td><code>yarn restore</code></td><td>Drop, recreate, and restore the dev DB from <code>database/backups/backup.sql</code></td></tr><tr><td><code>yarn redis</code></td><td>Start a local Redis server (project-local build)</td></tr><tr><td><code>yarn redis:stop</code></td><td>Stop the local Redis server</td></tr><tr><td><code>yarn sql fix1</code></td><td>Compile JS fixtures into <code>test/fixtures/fix1.sql</code> (run automatically by <code>yarn test</code>)</td></tr><tr><td><code>yarn test</code> / <code>yarn t</code></td><td>Full test suite: <code>yarn lang</code> → <code>yarn sql fix1</code> → jest <code>--runInBand</code></td></tr><tr><td><code>yarn ngrok</code></td><td>Open a public tunnel to port 8000 (for inbound webhook testing)</td></tr><tr><td><code>yarn ngrok:auth &lt;token&gt;</code></td><td>One-time ngrok auth token setup</td></tr><tr><td><code>yarn gulp</code></td><td>Start the Gulp watcher (auto-recompile mailer previews and locales on file change)</td></tr><tr><td><code>yarn format</code> / <code>yarn lint</code></td><td>Run the code formatter</td></tr><tr><td><code>yarn seed</code></td><td>Load seed data into the development database</td></tr><tr><td><code>yarn knowledge [product] [--prune]</code></td><td>Upsert product knowledge from <code>knowledge/</code> into the DB (idempotent; <code>--prune</code> removes rows no longer in the manifest)</td></tr></tbody></table><hr><h2 id="running-locally" tabindex="-1">Running Locally <a class="header-anchor" href="#running-locally" aria-label="Permalink to &quot;Running Locally&quot;">​</a></h2><p>The app has three processes. Run each in a separate terminal:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> s</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # web server — handles HTTP requests (port 8000)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> w</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">     # worker — processes Bull background jobs from Redis queues</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cron</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # clock — fires scheduled cronjobs and enqueues jobs on schedule</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Why three terminals?</strong> Each process has a distinct responsibility. The web server never runs jobs directly — it enqueues them and returns immediately. The worker dequeues and processes them. The clock triggers scheduled work on time. If the worker is not running, enqueued jobs pile up in Redis and never execute. If the clock is not running, no scheduled work fires.</p><p>Both <strong>Postgres and Redis must be running</strong> before starting any of the three processes. The app will fail to boot without them.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> redis</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # start local Redis if not already running</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><hr><h2 id="environment-setup" tabindex="-1">Environment Setup <a class="header-anchor" href="#environment-setup" aria-label="Permalink to &quot;Environment Setup&quot;">​</a></h2><p>Copy the template and fill in the required values:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/.env.template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/.env.development</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/.env.template</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/.env.test</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Required variables:</strong></p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th></tr></thead><tbody><tr><td><code>DATABASE_URL</code></td><td>Postgres connection string</td></tr><tr><td><code>REDIS_URL</code></td><td>Redis connection string</td></tr><tr><td><code>ACCESS_TOKEN_SECRET</code></td><td>JWT signing secret for access tokens</td></tr><tr><td><code>REFRESH_TOKEN_SECRET</code></td><td>JWT signing secret for refresh tokens</td></tr><tr><td><code>PORT</code></td><td>HTTP port (default: 8000)</td></tr><tr><td><code>API_VERSION</code></td><td>e.g. <code>v1</code></td></tr></tbody></table><p>Use separate databases for development and test — the test suite calls <code>sync({ force: true })</code> which wipes and recreates the schema before every run.</p><hr><h2 id="database-management" tabindex="-1">Database Management <a class="header-anchor" href="#database-management" aria-label="Permalink to &quot;Database Management&quot;">​</a></h2><h3 id="migrations" tabindex="-1">Migrations <a class="header-anchor" href="#migrations" aria-label="Permalink to &quot;Migrations&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mg</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # apply pending migrations (development)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migrate:prod</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # apply pending migrations (production)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rb</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # roll back the last migration (development)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rollback:prod</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # roll back the last migration (production)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>Generate a new migration file:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># New table (model)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./node_modules/.bin/sequelize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> model:create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> development</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> NewModel</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --attributes</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> col:type</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># New columns on an existing table</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./node_modules/.bin/sequelize</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> migration:create</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> development</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add-cols-colName-to-TableName-tbl</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Rename the generated file to the project convention immediately after generation — see <a href="../conventions.txt">docs/conventions.txt</a> for the format.</p><h3 id="backup-restore" tabindex="-1">Backup &amp; Restore <a class="header-anchor" href="#backup-restore" aria-label="Permalink to &quot;Backup &amp; Restore&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> backup</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # pg_dump orbital_dev &gt; database/backups/backup.sql</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> restore</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # drop + recreate orbital_dev, then restore from backup</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Use <code>yarn backup</code> before any risky migration in development.</p><hr><h2 id="deploying-to-heroku" tabindex="-1">Deploying to Heroku <a class="header-anchor" href="#deploying-to-heroku" aria-label="Permalink to &quot;Deploying to Heroku&quot;">​</a></h2><h3 id="procfile" tabindex="-1">Procfile <a class="header-anchor" href="#procfile" aria-label="Permalink to &quot;Procfile&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>release: yarn migrate:prod</span></span>
<span class="line"><span>web:     node --optimize_for_size --max_old_space_size=480 --gc_interval=100 index.js</span></span>
<span class="line"><span>worker:  node --optimize_for_size --max_old_space_size=480 --gc_interval=100 worker.js</span></span>
<span class="line"><span>clock:   node --optimize_for_size --max_old_space_size=480 --gc_interval=100 cronjobs.js</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>The <code>release</code> phase runs <code>yarn migrate:prod</code> on every deploy. If it fails, the new release does not go live. This guarantees migrations always run before new code takes traffic.</p><p>Run exactly <strong>one clock dyno</strong> in production. Running two would double-fire every scheduled job.</p><h3 id="first-time-setup" tabindex="-1">First-time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-time Setup&quot;">​</a></h3><ol><li>Create a Heroku app.</li><li>Add the Heroku PostgreSQL and Heroku Redis add-ons.</li><li>Set config variables — either manually in the Heroku dashboard or via <code>config/heroku-sync.js</code>.</li><li>Connect the repo&#39;s <code>main</code> branch to the Heroku app.</li><li>Click Deploy.</li><li>(Optional) Add a custom domain and SSL certificate.</li></ol><h3 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h3><p>Sync local env to Heroku:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config/heroku-sync.js</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>This script reads your local config file and pushes the values to <code>heroku config:set</code>. Review it before running — it will overwrite any variable already set on the app.</p><h3 id="shipping-knowledge-content-to-production" tabindex="-1">Shipping Knowledge Content to Production <a class="header-anchor" href="#shipping-knowledge-content-to-production" aria-label="Permalink to &quot;Shipping Knowledge Content to Production&quot;">​</a></h3><p>The <code>Procfile</code> release phase also runs <code>yarn knowledge --prune production</code> on every deploy. This upserts the committed <code>knowledge/</code> folder into the production DB (idempotent) and prunes rows no longer in the manifests. To ship updated knowledge content:</p><ol><li>Regenerate the <code>knowledge/</code> folder: <code>yarn export:content</code></li><li>Commit the updated files.</li><li>Deploy — the release phase handles the rest.</li></ol><hr><h2 id="health-readiness-probes" tabindex="-1">Health &amp; Readiness Probes <a class="header-anchor" href="#health-readiness-probes" aria-label="Permalink to &quot;Health &amp; Readiness Probes&quot;">​</a></h2><p>Two infrastructure endpoints are defined in <code>routes.js</code>. They bypass the action/controller pattern intentionally — they are infra, not features. The global rate limiter has a <code>skip</code> for both so probes are never throttled.</p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Type</th><th>What it checks</th><th>Used for</th></tr></thead><tbody><tr><td><code>GET /health</code></td><td>Liveness</td><td>Process is up — <strong>no dependency checks</strong></td><td>Platform restart decision</td></tr><tr><td><code>GET /ready</code></td><td>Readiness</td><td><code>db.authenticate()</code> + Redis <code>ping</code></td><td>Load balancer drain</td></tr></tbody></table><p>During graceful shutdown, <code>middleware/exit.js</code> intercepts both and returns <code>503</code> before they reach the route handler — no extra drain logic needed in the handlers themselves.</p><p><strong>Heroku note:</strong> Heroku routes by port-binding and restarts on crash rather than using readiness probes, so on Heroku <code>/health</code> is primarily for uptime monitors and <code>/ready</code> for dashboards. Both are essential if you move to k8s or ECS.</p><hr><h2 id="ngrok-—-testing-inbound-webhooks-locally" tabindex="-1">ngrok — Testing Inbound Webhooks Locally <a class="header-anchor" href="#ngrok-—-testing-inbound-webhooks-locally" aria-label="Permalink to &quot;ngrok — Testing Inbound Webhooks Locally&quot;">​</a></h2><p>Third-party providers (Stripe, Google, Twilio, etc.) cannot reach <code>localhost</code>. ngrok opens a public tunnel to your local server so their webhook calls reach your handler during development.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ngrok:auth</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">toke</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # one-time setup — paste the token from your ngrok account dashboard</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">yarn</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ngrok</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # open a public tunnel to port 8000</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Usage:</p><ol><li>Start the server: <code>yarn s</code></li><li>Start the tunnel: <code>yarn ngrok</code></li><li>ngrok prints a public URL like <code>https://abc123.ngrok.io</code>.</li><li>Register <code>https://abc123.ngrok.io/v1/&lt;feature&gt;/&lt;webhookaction&gt;</code> in the third party&#39;s dashboard.</li><li>Trigger an event on their side — the call flows through the tunnel to your local handler.</li></ol><p><strong>Free-tier caveat:</strong> The public URL changes every time you restart ngrok. Re-register the new URL with the provider after each restart.</p><p>Full notes in <a href="../ngrok.txt">docs/ngrok.txt</a>.</p><hr><h2 id="troubleshooting-—-common-gotchas" tabindex="-1">Troubleshooting — Common Gotchas <a class="header-anchor" href="#troubleshooting-—-common-gotchas" aria-label="Permalink to &quot;Troubleshooting — Common Gotchas&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Cause &amp; fix</th></tr></thead><tbody><tr><td>Tests hang and never exit after passing</td><td>Connections were not closed. Every test file needs an <code>afterAll</code> that closes the queue, socket, DB, and app.</td></tr><tr><td>Test suite won&#39;t start — missing i18n key error</td><td>A <code>.__(&#39;KEY&#39;)</code> call references a key not defined in <code>languages/*.js</code>. Add the key and run <code>yarn lang</code>. <code>yarn test</code> runs <code>yarn lang</code> first and fails fast.</td></tr><tr><td>Env variables are <code>undefined</code> in tests</td><td><code>process.env</code> was read before <code>dotenv</code> loaded. In test files, <code>require(&#39;dotenv&#39;).config(...)</code> must run before destructuring <code>process.env</code>.</td></tr><tr><td>A job is enqueued but nothing happens</td><td>The worker is not running. Start <code>yarn w</code>. Background jobs only execute while the worker process is up with Redis available.</td></tr><tr><td>A scheduled cronjob never fires</td><td>The clock process is not running. Start <code>yarn cron</code> (and <code>yarn w</code> to process what it enqueues). In production, ensure exactly one clock dyno.</td></tr><tr><td>A row you know exists comes back <code>null</code></td><td>A default scope (usually soft-delete / <code>paranoid: true</code>) is hiding it. Use <code>Model.scope(null).findByPk(...)</code> to bypass.</td></tr><tr><td>Parallel test suites fail intermittently</td><td>Run with <code>--runInBand</code>. Test suites share one test DB and race on <code>sync({ force: true })</code> without it. <code>yarn test</code> already passes this flag.</td></tr><tr><td><code>401</code> on a request you expected to be authed</td><td>The <code>Authorization</code> header prefix must match the user type: <code>jwt-user</code> for users, <code>jwt-admin</code> for admins.</td></tr><tr><td>Connection refused on boot</td><td>Postgres and/or Redis are not running. Both are required to start the app and run the test suite.</td></tr><tr><td>i18n / locale changes do not show up</td><td>You edited <code>locales/*.json</code> directly. Those are compiled output — never edit them. Edit <code>languages/*.js</code> and run <code>yarn lang</code>.</td></tr><tr><td>FK constraint error when loading fixtures</td><td><code>database/sequence.js</code> is out of order. Tables must be listed in dependency order (parent before child) so the SQL fixture inserts rows in the right sequence.</td></tr><tr><td><code>yarn del</code> was skipped and a broken export remains</td><td>Running <code>rm</code> instead of <code>yarn del</code> leaves a dead export in <code>actions/index.js</code> or <code>tasks/index.js</code>. Always use <code>yarn del</code> — it removes the file and cleans the export.</td></tr></tbody></table>`,61)])])}const k=t(i,[["render",o]]);export{u as __pageData,k as default};
